import{_ as e,o as t,c as r,ai as s}from"./chunks/framework.CsYGeNYI.js";const f=JSON.parse('{"title":"VPS 托管","description":"","frontmatter":{"read_when":["你想在云端运行 Gateway 网关","你需要 VPS/托管指南的快速索引"],"summary":"OpenSoul 的 VPS 托管中心（Oracle/Fly/Hetzner/GCP/exe.dev）","title":"VPS 托管","x-i18n":{"generated_at":"2026-02-03T10:12:57Z","model":"claude-opus-4-5","provider":"pi","source_hash":"7749b479b333aa5541e7ad8b0ff84e9f8f6bd10d7188285121975cb893acc037","source_path":"vps.md","workflow":15}},"headers":[],"relativePath":"zh-CN/vps.md","filePath":"zh-CN/vps.md","lastUpdated":null}'),o={name:"zh-CN/vps.md"};function l(n,a,i,d,c,h){return t(),r("div",null,[...a[0]||(a[0]=[s('<h1 id="vps-托管" tabindex="-1"><a class="header-anchor" href="#vps-托管">#</a> VPS 托管</h1><p>本中心链接到支持的 VPS/托管指南，并在高层次上解释云部署的工作原理。</p><h2 id="选择提供商" tabindex="-1"><a class="header-anchor" href="#选择提供商">#</a> 选择提供商</h2><ul><li><strong>Railway</strong>（一键 + 浏览器设置）：<a href="/docs/install/railway">Railway</a></li><li><strong>Northflank</strong>（一键 + 浏览器设置）：<a href="/docs/install/northflank">Northflank</a></li><li><strong>Oracle Cloud（永久免费）</strong>：<a href="/docs/platforms/oracle">Oracle</a> — $0/月（永久免费，ARM；容量/注册可能不太稳定）</li><li><strong>Fly.io</strong>：<a href="/docs/install/fly">Fly.io</a></li><li><strong>Hetzner（Docker）</strong>：<a href="/docs/install/hetzner">Hetzner</a></li><li><strong>GCP（Compute Engine）</strong>：<a href="/docs/install/gcp">GCP</a></li><li><strong>exe.dev</strong>（VM + HTTPS 代理）：<a href="/docs/install/exe-dev">exe.dev</a></li><li><strong>AWS（EC2/Lightsail/免费套餐）</strong>：也运行良好。视频指南： <a href="https://x.com/techfrenAJ/status/2014934471095812547" target="_blank" rel="noreferrer">https://x.com/techfrenAJ/status/2014934471095812547</a></li></ul><h2 id="云设置的工作原理" tabindex="-1"><a class="header-anchor" href="#云设置的工作原理">#</a> 云设置的工作原理</h2><ul><li><strong>Gateway 网关运行在 VPS 上</strong>并拥有状态 + 工作区。</li><li>你通过<strong>控制 UI</strong> 或 <strong>Tailscale/SSH</strong> 从笔记本电脑/手机连接。</li><li>将 VPS 视为数据源并<strong>备份</strong>状态 + 工作区。</li><li>安全默认：将 Gateway 网关保持在 loopback 上，通过 SSH 隧道或 Tailscale Serve 访问。 如果你绑定到 <code>lan</code>/<code>tailnet</code>，需要 <code>gateway.auth.token</code> 或 <code>gateway.auth.password</code>。</li></ul><p>远程访问：<a href="/docs/gateway/remote">Gateway 网关远程访问</a> 平台中心：<a href="/docs/platforms/index">平台</a></p><h2 id="在-vps-上使用节点" tabindex="-1"><a class="header-anchor" href="#在-vps-上使用节点">#</a> 在 VPS 上使用节点</h2><p>你可以将 Gateway 网关保持在云端，并在本地设备（Mac/iOS/Android/无头）上配对<strong>节点</strong>。节点提供本地屏幕/摄像头/canvas 和 <code>system.run</code> 功能，而 Gateway 网关保持在云端。</p><p>文档：<a href="/docs/nodes/index">节点</a>，<a href="/docs/cli/nodes">节点 CLI</a></p>',10)])])}const g=e(o,[["render",l]]);export{f as __pageData,g as default};
